mapper.insert:
INSERT INTO TB_ALIMXX(
            USER_NUMB
          , ALIM_NUMB
          , ALIM_SITU
          , TEMP_CODE
          , ALIM_TITL
          , ALIM_CONT
          , LINK_URLX
          , READ_YSNO
          , SEND_DATE
          , DELT_YSNO
) VALUES(   #{userNumb}
          , (
                SELECT NVL(MAX(ALIM_NUMB), 0) + 1
                  FROM TB_ALIMXX
                 WHERE USER_NUMB = #{userNumb}
            )
          , #{alimSitu}
          , #{tempCode}
          , #{alimTitl}
          , #{alimCont}
          , #{linkUrlx}
          , #{readYsno}
          , SYSDATE
          , #{deltYsno}
)
